  1→"use client";
  2→
  3→import { useCallback, useState } from "react";
  4→import { useDropzone } from "react-dropzone";
  5→import { Upload, FileText, CheckCircle, XCircle, Loader } from "lucide-react";
  6→import api from "@/lib/api";
  7→
  8→interface UploadResult {
  9→  uploaded: number;
 10→  failed: number;
 11→  resume_ids: number[];
 12→  errors: string[];
 13→}
 14→
 15→export default function UploadPage() {
 16→  const [files, setFiles] = useState<File[]>([]);
 17→  const [uploading, setUploading] = useState(false);
 18→  const [result, setResult] = useState<UploadResult | null>(null);
 19→
 20→  const onDrop = useCallback((accepted: File[]) => {
 21→    setFiles((prev) => [...prev, ...accepted]);
 22→    setResult(null);
 23→  }, []);
 24→
 25→  const { getRootProps, getInputProps, isDragActive } = useDropzone({
 26→    onDrop,
 27→    accept: {
 28→      "application/pdf": [".pdf"],
 29→      "application/vnd.openxmlformats-officedocument.wordprocessingml.document": [".docx"],
 30→    },
 31→    multiple: true,
 32→  });
 33→
 34→  const removeFile = (index: number) => {
 35→    setFiles((prev) => prev.filter((_, i) => i !== index));
 36→  };
 37→
 38→  const handleUpload = async () => {
 39→    if (files.length === 0) return;
 40→    setUploading(true);
 41→    setResult(null);
 42→
 43→    const formData = new FormData();
 44→    files.forEach((file) => formData.append("files", file));
 45→
 46→    try {
 47→      const res = await api.post("/resumes/upload", formData, {
 48→        headers: { "Content-Type": "multipart/form-data" },
 49→        timeout: 300000,
 50→      });
 51→      setResult(res.data);
 52→      setFiles([]);
 53→    } catch (err: unknown) {
 54→      const message = err instanceof Error ? err.message : "Upload failed";
 55→      setResult({ uploaded: 0, failed: files.length, resume_ids: [], errors: [message] });
 56→    } finally {
 57→      setUploading(false);
 58→    }
 59→  };
 60→
 61→  return (
 62→    <div className="space-y-6 max-w-2xl">
 63→      <h1 className="text-2xl font-bold text-zinc-900 dark:text-white">Upload Resumes</h1>
 64→
